// Use the zero-dep lean validator (no Ajv, no fs) so this module bundles
// cleanly for Cloudflare Workers / Edge runtimes without pulling node:fs.
// Behaviorally equivalent to validateManifest from @visitportal/spec —
// the conformance suite verifies "ajv↔lean agree on all manifest vectors"
// (see packages/spec/conformance/self-test.ts).
import { leanValidate } from "@visitportal/spec/lean-validator";
import { ManifestBuildError } from "./errors.js";
export function manifest(options) {
    const built = {
        portal_version: options.portal_version ?? "0.1",
        name: options.name,
        brief: options.brief,
        tools: options.tools.map(stripHandler),
        call_endpoint: options.call_endpoint,
        auth: options.auth ?? "none",
        pricing: options.pricing ?? { model: "free" },
    };
    return ensureManifest(built);
}
export function ensureManifest(input) {
    const duplicateNames = findDuplicateToolNames(input.tools);
    if (duplicateNames.length > 0) {
        throw new ManifestBuildError(duplicateNames.map((name) => `duplicate tool name: '${name}'`));
    }
    const result = leanValidate(input);
    if (!result.ok) {
        throw new ManifestBuildError(result.errors);
    }
    return input;
}
function stripHandler(tool) {
    const out = { name: tool.name };
    if (tool.description !== undefined)
        out.description = tool.description;
    if (tool.params !== undefined)
        out.params = tool.params;
    if (tool.paramsSchema !== undefined)
        out.paramsSchema = tool.paramsSchema;
    return out;
}
function findDuplicateToolNames(tools) {
    const seen = new Set();
    const duplicates = new Set();
    for (const tool of tools) {
        if (seen.has(tool.name))
            duplicates.add(tool.name);
        seen.add(tool.name);
    }
    return [...duplicates];
}
